frappe.ui.form.on('Tender', {
    refresh: function(frm) {
        
        frm.add_custom_button('Courier Details', function() {
            frappe.new_doc('Courier Details', {
                tender_id: frm.doc.name,
                consignee_name: frm.doc.consignee_name
            });
        }, 'Create');  

        frm.add_custom_button('Tender Out Register', function() {
            frappe.new_doc('Tender Out Register', {});
        }, 'Create');

        if (frm.doc.status === 'Qualified' && frm.doc.qualified_status === 'Purchase Order') {
            frm.add_custom_button('Make SD', function() {
                let doc = frappe.model.get_new_doc('Secure Deposite');
                doc.tender_id = frm.doc.name;
                
                frappe.ui.form.make_quick_entry('Secure Deposite', null, null, doc);
            });
        }
    }
});

frappe.ui.form.on('Tender', {
    refresh: function(frm) {
        const today = frappe.datetime.get_today();
        const tomorrow = frappe.datetime.add_days(today, 1);
        const dueDate = frm.doc.due_date?.split(' ')[0];

        if (dueDate === tomorrow) {
            frappe.msgprint({
                title: '⚠️ Tender Due Date Reminder',
                message: `
                    <div style="line-height:2">
                        <b>Tender ID:</b> ${frm.doc.name}<br>
                        <b>Product Name:</b> ${frm.doc.title}<br>
                        <b>Due Date:</b> ${frm.doc.due_date}<br>
                        <b>Supplier:</b> ${frm.doc.supplier_name}<br>
                        <b>EMD:</b> ₹${frm.doc.emd}<br><br>
                        <span style="color:red;font-weight:bold;">
                            Tomorrow is due date, Please Submit All Documents!!
                        </span>
                    </div>
                `,
                indicator: 'orange'
            });
        }
    }
});

frappe.ui.form.on('Tender', {
    refresh: function(frm) {
        apply_status_rules(frm);
        control_courier_button(frm);
    },

    status: function(frm) {
        apply_status_rules(frm);
        control_courier_button(frm);
    }
});

function apply_status_rules(frm) {
    const status = frm.doc.status;

    if (status === 'Draft') {
        set_fields_read_only(frm, ['bid_acknowledgement'], true);

        frm.set_df_property('tender_documents', 'cannot_add_rows', true);
        frm.set_df_property('tender_documents', 'cannot_delete_rows', true);

        frappe.show_alert({
            message: '📝 Draft: Fill basic information. Documents cannot be uploaded yet.',
            indicator: 'blue'
        });
    }

    else if (status === 'In Progress') {
        const mandatory_fields = [
            'tender_id', 'title', 'district', 'vanue',
            'consignee_name', 'issue_date', 'due_date',
            'estimated_value', 'supplier_name', 'emd',
            'gem_product_link', 'product_authorization_no'
        ];

        mandatory_fields.forEach(field => {
            frm.set_df_property(field, 'reqd', 1);
        });

        let missing = [];
        mandatory_fields.forEach(field => {
            if (!frm.doc[field] || frm.doc[field] === '0' || frm.doc[field] === 0) {
                missing.push(frappe.meta.get_label('Tender', field));
            }
        });

        if (missing.length > 0) {
            frappe.msgprint({
                title: '⚠️ Required Fields for In Progress',
                message: `Please fill the following fields before setting status to In Progress:<br><b>${missing.join(', ')}</b>`,
                indicator: 'orange'
            });
            frm.set_value('status', 'Draft');
            return;
        }

        frm.set_df_property('tender_documents', 'cannot_add_rows', true);
        frm.set_df_property('tender_documents', 'cannot_delete_rows', true);
        set_fields_read_only(frm, ['bid_acknowledgement'], true);

        frappe.show_alert({
            message: '🔄 In Progress: Core fields filled. Now move to Submitted.',
            indicator: 'yellow'
        });
    }

    else if (status === 'Submitted') {
        frm.set_df_property('tender_documents', 'cannot_add_rows', false);
        frm.set_df_property('tender_documents', 'cannot_delete_rows', false);
        set_fields_read_only(frm, ['bid_acknowledgement'], false);

        frappe.show_alert({
            message: '✅ Submitted: You can now upload Tender Documents and send Courier.',
            indicator: 'green'
        });
    }

    else if (status === 'Won' || status === 'Lost') {
        frm.set_df_property('tender_documents', 'cannot_add_rows', true);
        frm.set_df_property('tender_documents', 'cannot_delete_rows', true);
        set_fields_read_only(frm, ['bid_acknowledgement'], true);
    }

    frm.refresh_fields();
}

function control_courier_button(frm) {
    if (frm.doc.status === 'Submitted' && !frm.doc.__islocal) {
        frm.add_custom_button(__('Tender Out Register'), function() {
            frappe.new_doc('Tender Out Register', {
                tender: frm.doc.name,
                tender_id: frm.doc.tender_id
            });
        }, __('Create'));
    }
}

function set_fields_read_only(frm, fields, is_readonly) {
    fields.forEach(field => {
        frm.set_df_property(field, 'read_only', is_readonly ? 1 : 0);
    });
}

frappe.ui.form.on('Tender', {
    refresh: function(frm) {

        // ── existing buttons ──
        frm.add_custom_button('Courier Details', function() {
            frappe.new_doc('Courier Details', {
                tender_id: frm.doc.name,
                consignee_name: frm.doc.consignee_name
            });
        }, 'Create');

        frm.add_custom_button('Tender Out Register', function() {
            frappe.new_doc('Tender Out Register', {
                tender_id: frm.doc.name
            });
        }, 'Create');

        // ── EMD Return Alert ──
        if (frm.doc.status === 'Disqualified') {
            show_emd_alert(frm);
        }
    }
});

function show_emd_alert(frm) {

    // localStorage key — per tender unique
    let key = 'emd_received_' + frm.doc.name;
    let remind_key = 'emd_remind_' + frm.doc.name;

    // Check karo k EMD already mali gayi che
    if (localStorage.getItem(key) === 'done') return;

    // Check karo k "Remind Later" time set che
    let remind_time = localStorage.getItem(remind_key);
    if (remind_time && new Date().getTime() < parseInt(remind_time)) return;

    // Modal dialog banavo
    let d = new frappe.ui.Dialog({
        title: '⚠️ EMD Return Pending',
        fields: [
            {
                fieldtype: 'HTML',
                options: `
                    <div style="padding:10px 0;">
                        <p style="font-size:14px; color:#374151;">
                            <b>Tender:</b> ${frm.doc.name}<br>
                            <b>Consignee:</b> ${frm.doc.consignee_name || ''}<br>
                            <b>EMD Amount:</b> ₹ ${frm.doc.emd || '0'}<br><br>
                            <span style="color:#e02424; font-weight:bold;">
                                આ Tender Disqualified છે — EMD Return લેવાનું બાકી છે!
                            </span>
                        </p>
                    </div>
                `
            },
            {
                fieldtype: 'Select',
                fieldname: 'remind_after',
                label: 'Remind Me After',
                options: [
                    '30 Minutes',
                    '1 Hour',
                    '2 Hours',
                    '4 Hours',
                    '1 Day',
                    '3 Days'
                ],
                default: '1 Hour'
            }
        ],
        primary_action_label: '✅ EMD મળી ગઈ',
        primary_action: function() {
            // EMD received — permanently close
            localStorage.setItem(key, 'done');
            frappe.show_alert({
                message: 'EMD Return confirmed!',
                indicator: 'green'
            }, 4);
            d.hide();
        },
        secondary_action_label: '⏰ Remind Me Later',
        secondary_action: function() {
            let remind = d.get_value('remind_after');
            let ms = {
                '30 Minutes': 30 * 60 * 1000,
                '1 Hour':      1 * 60 * 60 * 1000,
                '2 Hours':     2 * 60 * 60 * 1000,
                '4 Hours':     4 * 60 * 60 * 1000,
                '1 Day':      24 * 60 * 60 * 1000,
                '3 Days':  3 * 24 * 60 * 60 * 1000
            }[remind] || 3600000;

            let remind_time = new Date().getTime() + ms;
            localStorage.setItem(remind_key, remind_time);

            frappe.show_alert({
                message: `${remind} પછી remind કરીશ!`,
                indicator: 'blue'
            }, 4);
            d.hide();
        }
    });

    d.show();
}
